import {
  Component, Input, Output, EventEmitter, signal,
  HostListener, ChangeDetectionStrategy,
} from '@angular/core';
import { CommonModule } from '@angular/common';

export interface UploadedFile {
  file:       File;
  preview?:   string;   // data-URL for images
  id:         string;
}

@Component({
  selector: 'app-file-upload',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './file-upload.component.html',
  styleUrls: ['./file-upload.component.css'],
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class FileUploadComponent {
  @Input() accept        = '*/*';
  @Input() multiple      = false;
  @Input() maxSizeMB     = 50;
  @Input() label         = 'Drop files here or click to browse';
  @Input() sublabel      = '';

  @Output() filesSelected = new EventEmitter<File[]>();
  @Output() fileRemoved   = new EventEmitter<string>();

  readonly isDragging  = signal(false);
  readonly uploadedFiles = signal<UploadedFile[]>([]);
  readonly error       = signal<string | null>(null);

  @HostListener('dragover', ['$event'])
  onDragOver(e: DragEvent): void {
    e.preventDefault();
    this.isDragging.set(true);
  }

  @HostListener('dragleave')
  onDragLeave(): void { this.isDragging.set(false); }

  @HostListener('drop', ['$event'])
  onDrop(e: DragEvent): void {
    e.preventDefault();
    this.isDragging.set(false);
    const files = Array.from(e.dataTransfer?.files ?? []);
    this.processFiles(files);
  }

  onFileInputChange(event: Event): void {
    const input = event.target as HTMLInputElement;
    this.processFiles(Array.from(input.files ?? []));
    input.value = '';
  }

  removeFile(id: string): void {
    this.uploadedFiles.update((files) => files.filter((f) => f.id !== id));
    this.fileRemoved.emit(id);
    // Notify parent of the updated complete file list after removal
    this.filesSelected.emit(this.uploadedFiles().map((uf) => uf.file));
  }

  clearAll(): void {
    this.uploadedFiles.set([]);
    this.filesSelected.emit([]);
  }

  private processFiles(files: File[]): void {
    this.error.set(null);
    const maxBytes = this.maxSizeMB * 1024 * 1024;

    const valid = files.filter((f) => {
      if (f.size > maxBytes) {
        this.error.set(`"${f.name}" exceeds ${this.maxSizeMB} MB limit.`);
        return false;
      }
      return true;
    });

    if (!valid.length) return;

    // Generate previews for images
    const toAdd: UploadedFile[] = valid.map((f) => ({
      file:    f,
      id:      `${Date.now()}-${Math.random()}`,
      preview: undefined,
    }));

    if (!this.multiple) {
      this.uploadedFiles.set(toAdd.slice(0, 1));
    } else {
      this.uploadedFiles.update((cur) => [...cur, ...toAdd]);
    }

    // Build previews async
    toAdd.forEach((uf) => {
      if (uf.file.type.startsWith('image/')) {
        const reader = new FileReader();
        reader.onload = (e) => {
          this.uploadedFiles.update((list) =>
            list.map((f) => (f.id === uf.id ? { ...f, preview: e.target?.result as string } : f))
          );
        };
        reader.readAsDataURL(uf.file);
      }
    });

    // Emit the FULL current file list (not just newly added) so parent always has accurate state
    this.filesSelected.emit(this.uploadedFiles().map((uf) => uf.file));
  }

  formatSize(bytes: number): string {
    if (bytes < 1024)       return `${bytes} B`;
    if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
    return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
  }
}
<!-- Drop Zone -->
<div
  class="drop-zone min-h-[220px] p-8 relative"
  [class.drop-zone-active]="isDragging()"
  (click)="fileInput.click()">

  <input #fileInput type="file" [accept]="accept" [multiple]="multiple" (change)="onFileInputChange($event)">

  <div class="text-center pointer-events-none">
    <!-- Upload Icon -->
    <div class="w-16 h-16 mx-auto mb-4 bg-primary-50 dark:bg-primary-950/50 rounded-2xl flex items-center justify-center"
      [class.scale-110]="isDragging()" class="transition-transform duration-200">
      <svg class="w-8 h-8 text-primary-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path stroke-linecap="round" stroke-linejoin="round" stroke-width="1.5"
          d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12"/>
      </svg>
    </div>

    <p class="font-semibold text-slate-700 dark:text-slate-200 text-lg mb-1">{{ label }}</p>
    <p *ngIf="sublabel" class="text-sm text-slate-500 dark:text-slate-400 mb-2">{{ sublabel }}</p>
    <p class="text-xs text-slate-400 dark:text-slate-500">Maximum file size: {{ maxSizeMB }} MB</p>
  </div>
</div>

<!-- Error -->
<p *ngIf="error()" class="mt-2 text-sm text-red-500 flex items-center gap-1.5">
  <svg class="w-4 h-4 flex-shrink-0" fill="currentColor" viewBox="0 0 20 20">
    <path fill-rule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7 4a1 1 0 11-2 0 1 1 0 012 0zm-1-9a1 1 0 00-1 1v4a1 1 0 102 0V6a1 1 0 00-1-1z" clip-rule="evenodd"/>
  </svg>
  {{ error() }}
</p>

<!-- File List -->
<div *ngIf="uploadedFiles().length" class="mt-4 space-y-2 animate-fade-in">
  <div class="flex items-center justify-between mb-2">
    <span class="text-sm font-medium text-slate-600 dark:text-slate-300">
      {{ uploadedFiles().length }} file{{ uploadedFiles().length > 1 ? 's' : '' }} selected
    </span>
    <button (click)="clearAll(); $event.stopPropagation()" class="text-xs text-red-500 hover:text-red-700 transition-colors">
      Clear all
    </button>
  </div>

  <div *ngFor="let uf of uploadedFiles()"
    class="flex items-center gap-3 p-3 bg-slate-50 dark:bg-slate-800 rounded-xl border border-slate-200 dark:border-slate-700 group">

    <!-- Preview or icon -->
    <div class="w-10 h-10 rounded-lg overflow-hidden flex-shrink-0 bg-white dark:bg-slate-700 border border-slate-200 dark:border-slate-600 flex items-center justify-center">
      <img *ngIf="uf.preview; else fileIcon" [src]="uf.preview" alt="" class="w-full h-full object-cover">
      <ng-template #fileIcon>
        <svg class="w-5 h-5 text-slate-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path stroke-linecap="round" stroke-linejoin="round" stroke-width="1.5"
            d="M7 21h10a2 2 0 002-2V9.414a1 1 0 00-.293-.707l-5.414-5.414A1 1 0 0012.586 3H7a2 2 0 00-2 2v14a2 2 0 002 2z"/>
        </svg>
      </ng-template>
    </div>

    <!-- Info -->
    <div class="flex-1 min-w-0">
      <p class="text-sm font-medium text-slate-700 dark:text-slate-200 truncate">{{ uf.file.name }}</p>
      <p class="text-xs text-slate-400">{{ formatSize(uf.file.size) }}</p>
    </div>

    <!-- Remove -->
    <button (click)="removeFile(uf.id); $event.stopPropagation()"
